INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-d0d1b9a2-moex-00354', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司X1年7月1日向乙公司購入一公允價值為$600,000設備，並以所持有上市公司股票 為支付對價，該股票公允價值為$610,000。下列有關該交易之敘述，何者正確？', '["不論該股票為他公司股票或甲公司股票，設備成本均為$600,000", "不論該股票為他公司股票或甲公司股票，設備成本均為$610,000", "若該股票為他公司股票，設備成本為$600,000；若該股票為甲公司股票，設備成本為$610,000", "若該股票為他公司股票，設備成本為$610,000；若該股票為甲公司股票，設備成本為$600,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00355', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司X5年初有面額$10，股利率3%之非累積可轉換特別股10,000股流通在外，每股可轉換 為面額$10之普通股1股。X5年12月1日甲公司為促使該可轉換特別股之轉換，將轉換條件修 改為若於X6年3月底前轉換，則每股特別股可轉換為面額$10之普通股1.5股及獲得現金$5， 當日普通股股價為$40。X6年3月30日該10,000股可轉換特別股全數進行轉換，當日普通股股 價為$50。試問：該可轉換特別股對甲公司X5年及X6年稅前淨利之影響分別為何？', '["X5年及X6年均無影響", "X5年無影響，X6年減少$300,000", "X5年減少$250,000，X6年無影響", "X5年減少$250,000，X6年減少$50,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00356', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司屬於高耗能產業，為了推動永續發展，決定要逐步淘汰老舊工廠，朝向節能高效率的 潔淨生產目標邁進。公司基於關閉數座老舊廠房，於X8年12月1日宣布裁員計畫，要在4 個月內減少600位員工。如果自願離職者，每位員工可以獲得$70,000的離職金，但如果自願 離職人數不足600名，公司將資遣部分員工，直到員工人數減少總數達到600位。對於被公 司資遣的非自願離職員工，給予每位$35,000的離職金。X8年底，已有250位員工自願離職， 尚無非自願離職者，而公司預估總共會有400位員工選擇自願離職。請問甲公司於X8年底 的離職福利費用，應認列的金額為何？', '["$28,000,000", "$35,000,000", "$21,000,000", "$17,500,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00357', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '存貨為許多企業的重要資產之一，尤其對於買賣業與製造業來說，存貨常占流動資產的最高 比例。下列有關存貨與其會計處理的敘述，何者正確？', '["存貨的續後評價，應採成本與淨變現價值孰低衡量。其中淨變現價值，為個別企業預期於 正常營業出售存貨所能取得之淨額，故為企業特定價值", "國際會計準則第2號（IAS2）明確定義符合存貨資產的條件，依此存貨僅分為兩種，即買 賣業的商品存貨與製造業的製成品存貨", "在定期盤存制度中，進貨時，借記存貨；銷貨時，僅認列銷貨收入，先不記錄存貨減少的 部分；期末盤點後，認列期末存貨與銷貨成本", "國際會計準則第2號（IAS2）規範存貨成本的計算方法，應優先採用個別認定法，如個別 認定法不適當時，則允許使用加權平均法，並要求不得使用後進先出法與先進先出法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00358', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '「財務報導之觀念架構」說明一般用途財務報導之目的，係提供現在及潛在之投資人與債權人 於作成「決策」時所需之有用財務資訊。下列有關一般用途財務報導目的之敘述，何者錯誤？', '["此處所提到的「決策」，包含提供或結清貸款及其他形式之授信，與買入、賣出或持有權益 及債務工具", "依一般用途財務報導之目的，所提供的財務資訊，已經包含投資人與債權人所需之全部資訊", "投資人與債權人在進行決策時，需要企業之經濟資源、請求權與其變動等財務資訊，來評 估企業之未來現金流量", "對公司之管理階層行使表決或影響之權利，也包含在此處所提到的「決策」中，這有助強 化管理階層的課責性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00359', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '國際財務報導準則的四大財務報表，包含資產負債表、綜合損益表、權益變動表及現金流量 表。其中權益變動表，用於表達企業在某一期間內各項權益組成部分暨權益總額之變動。下 列關於權益變動表的敘述，何者錯誤？', '["權益變動表，一般具有連結綜合損益表與資產負債表的功能", "權益變動表中，對於本期綜合損益總額，應分別列示歸屬於母公司業主之總額及非控制權 益之總額", "權益變動表中，有關各權益組成部分在期初與期末帳面金額間之調節，僅本期淨利（或淨 損）需單獨揭露", "權益變動表中，有關各權益組成部分之期初餘額應加計「追溯適用及追溯重編之影響數」， 得到期初重編後餘額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00360', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '財務會計準則與稅法規定，往往導因於會計學理與租稅政策的觀點不同，使得兩者之間存在 許多差異。而所得稅的會計處理，就是要在財稅差異下，處理本期與未來租稅後果（本期所 得稅與遞延所得稅）。下列有關所得稅會計處理的敘述，何者正確？', '["會計利潤與課稅所得之間，如果是基於租稅政策與其他政策的考量，使兩者發生差異，且 其影響僅及於本期課稅所得者，屬於暫時性差異", "產品出售後的保固成本，會於銷貨時估列費用，而依稅法則需等實際發生保固相關支出時， 才可做為費用減除，此類差異屬於永久性差異", "所得稅費用，是指本期所得稅費用及遞延所得稅兩項目合計的金額", "對於某項資產的課稅基礎，是指其帳面金額減去未來期間報稅上與該資產有關之任何可減 除金額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00361', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '一般對權益的定義，是指資產減除負債後的剩餘價值，又稱為淨資產。而國際會計準則也有 定義，非金融資產也非金融負債的金融工具，就是屬於權益工具。下列為公司發行不同條件 之特別股應歸屬權益工具與否的敘述，何者錯誤？', '["甲公司發行具有可賣回（puttable）條件的特別股，即持有人可選擇將特別股賣回給發行的 甲公司，只要公司預期持有人不會執行賣回，則此特別股屬於權益工具", "乙公司發行具有強制贖回（mandatoryredemption）條件的特別股，即約定未來某天到期， 發行的乙公司會強制贖回，此特別股具負債特性", "丙公司發行具有可買回（callable）條件的特別股，即發行的丙公司可選擇是否將該特別股 買回，此特別股屬於權益工具", "丁公司發行可轉換特別股，即持有人可要求將特別股轉換為普通股，且轉換比例固定為一 股換一股，發行的丁公司在轉換時，有裁量權可無條件避免現金流出，則此特別股屬於權 益工具"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00362', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '負債準備與一般應付帳款不同，最主要的差異在於負債準備的清償義務，未來需支付之時點 或金額，在目前並不確定。下列四家公司對負債準備的會計處理，何者最不適當？', '["甲公司本年度銷售5,000個商品，依過去多年的營運經驗平均有2%的不良品，故公司根據 期望值將100個商品的維修成本，估列保固負債準備", "乙公司涉及侵犯他人專利權之官司，經律師評估有三種可能的結果：30%的機會不需賠償， 55%的機會需賠償500萬元，及15%的機會需賠償650萬元。假定無其他影響因素下，公 司可用最高發生機會的500萬元認列負債準備", "丙公司因市場競爭失利，決定關閉某一製造工廠，並進行重組。在估計重組的負債準備時， 公司可將關廠後出售廠房的預估利得，作為負債準備的減項", "丁公司因生產造成環境污染，除依法繳交罰金外，需支付附近居民補償金，其評估補償的 金額範圍是5千萬元至8千萬元，且在此範圍內各金額發生的可能性相同，則公司可用中 間值6千5百萬元來估列負債準備"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00363', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'essay', '依據我國審計準則 610號（原審計準則公報第 73號）「採用內部稽核人
